static int cbs_av1_assemble_fragment(CodedBitstreamUnit *au, const uint8_t *data, size_t size, size_t bit_offset)
{
    uint8_t *buf;
    int ret;

    if (au->type == AV_BUFFER_FLAG_CODEC_DATA) {
        av_log(au->cbs->fc, AV_LOG_ERROR, "AV1 codec initialization data is not supported.\n");
        return AVERROR(EINVAL);
    }

    if (!size)
        return 0;

    if (au->type == AV_BUFFER_FLAG_FRAME) {
        if (au->data)
            return AVERROR(EINVAL);

        av_log(au->cbs->fc, AV_LOG_WARNING, "AV1 fragmented bitstream is not supported.\n");
    }

    if (!au->data) {
        if (au->size) {
            av_log(au->cbs->fc, AV_LOG_ERROR, "AV1 bitstream fragment without a header is not supported.\n");
            return AVERROR(EINVAL);
        }

        au->data = av_buffer_alloc(size + AV_INPUT_BUFFER_PADDING_SIZE);
        if (!au->data)
            return AVERROR(ENOMEM);
        au->size = size;
        buf = au->data->data;
    } else {
        if (size > au->size - au->data_offset) {
            av_log(au->cbs->fc, AV_LOG_ERROR, "AV1 bitstream fragment too large.\n");
            return AVERROR(EINVAL);
        }

        buf = au->data->data + au->data_offset;
    }

    memcpy(buf, data, size);

    au->data_offset += size;
    au->size = FFMAX(au->size, au->data_offset);

    if (au->type == AV_BUFFER_FLAG_FRAME) {
        ret = ff_cbs_alloc_data_unit(au->cbs, au);
        if (ret < 0)
            return ret;

        ret = ff_cbs_read_unit(au->cbs, au, buf, size);
        if (ret < 0)
            return ret;

        au->data_ref = av_buffer_ref(au->data);
        if (!au->data_ref)
            return AVERROR(ENOMEM);
    }

    return 0;
}

