void SetStartType(SC_HANDLE schService, DWORD dwStartType)
{
    LPQUERY_SERVICE_CONFIG pBuf;
    DWORD dwBytesNeeded;
    DWORD dwOldCheckPoint;
    DWORD dwBytesThisTime;
    DWORD dwServiceType;
    DWORD dwStartType;
    DWORD dwError;
    DWORD dwOldStartType;

    if (QueryServiceConfig(schService, NULL, 0, &dwBytesNeeded))
    {
        //
        // QueryServiceConfig returned success, so the needed bytes
        // can be zero.
        //
        dwBytesNeeded = 0;
    }
    else
    {
        //
        // QueryServiceConfig failed with ERROR_INSUFFICIENT_BUFFER,
        // so get the needed bytes and allocate the buffer.
        //
        if (GetLastError() != ERROR_INSUFFICIENT_BUFFER)
        {
            goto cleanup;
        }
        pBuf = (LPQUERY_SERVICE_CONFIG)LocalAlloc(LPTR, dwBytesNeeded);
        if (pBuf == NULL)
        {
            goto cleanup;
        }
    }

    if (QueryServiceConfig(schService, pBuf, dwBytesNeeded, &dwBytesNeeded))
    {
        dwOldCheckPoint = 0;
        dwOldStartType = pBuf->dwStartType;
        dwServiceType = pBuf->dwServiceType;
        dwStartType = dwStartType;
        while (TRUE)
        {
            dwError = ChangeServiceConfig(schService,
                dwServiceType,
                dwStartType,
                pBuf->dwErrorControl,
                pBuf->lpBinaryPathName,
                pBuf->lpLoadOrderGroup,
                NULL,
                pBuf->lpDependencies,
                pBuf->lpServiceStartName,
                pBuf->lpPassword,
                pBuf->lpDisplayName);

            if (dwError == 0)
            {
                break;
            }
            else
            {
                if (dwError == ERROR_SERVICE_MARKED_FOR_DELETE)
                {
                    dwError = ERROR_INVALID_PARAMETER;
                    break;
                }
                else if (dwError != ERROR_SERVICE_EXISTS)
                {
                    break;
                }
                if (dwOldStartType != dwStartType)
                {
                    dwError = ERROR_INVALID_PARAMETER;
                    break;
                }
                if (dwOldCheckPoint == pBuf->dwCheckPoint)
                {
                    dwError = ERROR_INVALID_PARAMETER;
                    break;
                }
                dwOldCheckPoint = pBuf->dwCheckPoint;
                dwBytesThisTime = pBuf->dwWaitHint / 8;
                if (dwBytesThisTime < dwBytesNeeded / 8)
                {
                    dwBytesThisTime = dwBytesNeeded / 8;
                }
                if (dwBytesThisTime > 32)
                {
                    dwBytesThisTime = 32;
                }
                if (!QueryServiceConfig(schService, pBuf, dwBytesNeeded, &dwBytesNeeded))
                {
                    dwError = GetLastError();
                    break;
                }
            }
        }
        if (dwError == 0)
        {
            if (pBuf->dwStartType != dwStartType)
            {
                dwError = ERROR_INVALID_PARAMETER;
            }
        }
    }
    else
    {
        dwError = GetLastError();
    }

cleanup:
    if (pBuf != NULL)
    {
        LocalFree(pBuf);
    }
    if (dwError != 0)
    {
        SetLastError(dwError);
        return FALSE;
    }
    return TRUE;
}

