/*
 * Validate the hostname during TLS transport selection.
 */
static int tls_transport_valid_hostname(const char *hostname,
                                         pjsip_transport_type_e type)
{
    int i;

    for (i = 0; transport_names[i].name != NULL; i++) {
        if (type == transport_names[i].type) {
            if (strcmp(transport_names[i].name, hostname) == 0)
                return 1;
            else
                return 0;
        }
    }

    /* Unknown transport type. */
    return 0;
}

