static int ssl3_do_change_cipher_spec(SSL *s)
{
    unsigned char ccs[1];
    unsigned char al[SSL3_AL_HEADER_LENGTH];
    int al_len;

    if (!s->server) {
        /*
         * In TLSv1.3 and later we don't send this message.
         */
        if (s->version == TLS1_3_VERSION)
            return 1;
        ccs[0] = SSL3_MT_CHANGE_CIPHER_SPEC;
        if (!ssl3_write_bytes(s, SSL3_RT_CHANGE_CIPHER_SPEC, ccs, 1))
            return -1;
        if (!s->hit) {
            s->session->master_key_length =
                s->method->ssl3_enc->generate_master_secret(s,
                                                             s->
                                                             session->master_key,
                                                             s->session->
                                                             master_key_length,
                                                             s->
                                                             handshake_secret,
                                                             s->
                                                             handshake_secret_size);
            if (s->session->master_key_length == 0)
                return ssl3_send_alert(s, SSL3_AL_FATAL,
                                        SSL_AD_INTERNAL_ERROR);
            s->session->flags |= SSL_SESS_FLAG_TICKET_HAS_KEY;
        }
    } else {
        unsigned char *p;
        int al = SSL_AD_DECODE_ERROR;
        long n;

        n = s->method->ssl_get_message(s,
                                       SSL3_ST_SR_CHANGE,
                                       SSL3_ST_SR_CHANGE_A,
                                       SSL3_MT_CHANGE_CIPHER_SPEC, 16,
                                       &ok);

        if (!ok)
            return ((int)n);

        p = (unsigned char *)s->init_msg;

        if (*p != SSL3_MT_CHANGE_CIPHER_SPEC) {
            s->s3->tmp.message_type = *(p++);
            ssl3_send_alert(s, SSL3_AL_FATAL, SSL_AD_UNEXPECTED_MESSAGE);
            SSLerr(SSL_F_SSL3_DO_CHANGE_CIPHER_SPEC,
                   SSL_R_CCS_RECEIVED_EARLY);
            return -1;
        }
        p++;
        n -= 2;
