    zfs_fuid_map_handle_t *fuid_map_handle)
{
	zfs_acl_node_t *node;
	zfs_acl_t *acl;
	uint_t count;
	int err;

	if (src_aclp == NULL)
		return (0);

	/*
	 * If the source ACL is an empty ACL, then we're done.
	 */
	if (src_aclp->z_version == 0)
		return (0);

	if (dst_aclp == NULL)
		return (0);

	/*
	 * If the destination ACL is an empty ACL, then we need to
	 * create a new one.
	 */
	if (dst_aclp->z_version == 0) {
		err = zfs_acl_version_create(dst_aclp, type);
		if (err != 0)
			return (err);
	}

	/*
	 * If the destination ACL is not empty, then we need to
	 * add the new ACEs to the end of the ACL.
	 */
	node = NULL;
	acl = dst_aclp;
	while (acl->z_version != 0) {
		node = acl;
		acl = acl->z_next;
	}

	/*
	 * If the source ACL is not empty, then we need to
	 * add the new ACEs to the end of the ACL.
	 */
	count = 0;
	acl = src_aclp;
	while (acl->z_version != 0) {
		err = zfs_fuid_map_id(fuid_map_handle,
