		    acl->z_ace->z_type == ZFS_ACE_ACCESS_DENIED_ACE_TYPE ||
		    acl->z_ace->z_type == ZFS_ACE_SYSTEM_AUDIT_ACE_TYPE ||
		    acl->z_ace->z_type == ZFS_ACE_SYSTEM_ALARM_ACE_TYPE) {
			err = zfs_acl_node_create(acl->z_ace->z_type,
			    uid, gid, acl->z_ace->z_flags, acl->z_ace->z_access_mask,
			    &node, &acl);
			if (err != 0)
				return (err);
			count++;
		} else {
			err = zfs_acl_node_create(acl->z_ace->z_type,
			    acl->z_ace->z_who, acl->z_ace->z_access_mask, &node, &acl);
			if (err != 0)
				return (err);
			count++;
