int X509_cmp_time(const ASN1_TIME *s, const ASN1_TIME *t)
    {
        if ((s->type != t->type) || (s->length != t->length))
            return (s->type - t->type);
        if (s->type == V_ASN1_UTCTIME)
        {
            if ((s->data[6] > '9') || (s->data[7] > '9'))
                return 1;
            if ((t->data[6] > '9') || (t->data[7] > '9'))
                return -1;
            return (((s->data[6] - '0') * 10 + (s->data[7] - '0'))
                    - ((t->data[6] - '0') * 10 + (t->data[7] - '0')));
        }
        else
        {
            if ((s->data[4] > '9') || (s->data[5] > '9'))
                return 1;
            if ((t->data[4] > '9') || (t->data[5] > '9'))
                return -1;
            return (((s->data[4] - '0') * 10 + (s->data[5] - '0'))
                    - ((t->data[4] - '0') * 10 + (t->data[5] - '0')));
