#include "stdafx.h"
#include "WindowsServiceControl.h"
#include "WindowsServiceControlPriv.h"

void WindowsServiceControl::QuoteServicePath(wstring& servicePath)
{
	if (servicePath.empty())
		return;

	size_t len = servicePath.length();
	for (size_t i = 0; i < len; i++)
	{
		if (servicePath[i] == L' ')
		{
			servicePath.insert(i, 1, L'\"');
			len++;
			i++;
		}
		else if (servicePath[i] == L'\"')
		{
			servicePath.insert(i, 1, L'\\');
			len++;
			i++;
		}
	}
	servicePath.insert(0, 1, L'\"');
	servicePath.append(1, L'\"');
}

