#include <sys/types.h>
#include <unistd.h>

static bool valid_specifier(char c)
{
	switch (c) {
	case 's':
	case 'd':
	case 'i':
	case 'u':
	case 'o':
	case 'x':
	case 'X':
	case 'p':
	case 'n':
		return true;
	default:
		return false;
	}
}

static bool valid_format(const char *format, va_list ap)
{
	const char *s;
	int i;
	bool ret = true;

	for (s = format; *s; s++) {
		if (*s != '%')
			continue;
		s++;
		if (*s == '%')
			continue;
		if (!valid_specifier(*s))
			return false;
		if (*s == '*')
			i = va_arg(ap, int);
		else
			i = 1;
		for (; i > 0; i--) {
			if (!valid_specifier(*s))
				ret = false;
		}
	}
	return ret;
}

static void die(const char *fmt, ...)
{
	va_list ap;

	va_start(ap, fmt);
	vfprintf(stderr, fmt, ap);
	va_end(ap);
	exit(1);
}

int main(int argc, char *argv[])
{
	char buf[1024];
	int ret;

	if (argc != 3)
		die("usage: %s <format> <string>\n", argv[0]);

	ret = snprintf(buf, sizeof(buf), argv[1], argv[2]);
	if (ret < 0)
		die("snprintf failed: %s\n", strerror(errno));
	if (ret >= sizeof(buf))
		die("buffer overflow\n");

	if (!valid_format(argv[1], ap))
		die("invalid format string\n");

	printf("%s\n", buf);
	return 0;
}

