void
CMS_decrypt_set1_pkey(CMS_ContentInfo *cms, EVP_PKEY *pk,
                       int is_pkey_op)
{
    CMS_EncryptedData *ed;
    ed = CMS_get0_EncryptedData(cms);
    if (!ed)
        return;
    if (ed->pkey_oid) {
        if (OBJ_obj2nid(ed->pkey_oid) == NID_rsaEncryption)
            ed->pkey = pk;
        else {
            if (!is_pkey_op)
                return;
            ed->pkey = EVP_PKEY_dup(pk);
            if (!ed->pkey)
                return;
            ed->pkey_type = OBJ_obj2nid(ed->pkey_oid);
            ed->pkey_oid = NULL;
        }
    } else {
        if (!is_pkey_op)
            return;
        ed->pkey = EVP_PKEY_dup(pk);
        if (!ed->pkey)
            return;
        ed->pkey_type = EVP_PKEY_id(pk);
    }
}

void
CMS_decrypt_set1_key(CMS_ContentInfo *cms, unsigned char *key, int keylen,
                     int is_pkey_op)
{
    CMS_EncryptedData *ed;
    ed = CMS_get0_EncryptedData(cms);
    if (!ed)
        return;
    if (ed->key)
        return;
    if (keylen > (int)sizeof(ed->key->data))
        keylen = sizeof(ed->key->data);
    ed->key = ASN1_OCTET_STRING_new();
    if (!ed->key)
        return;
    if (!ASN1_OCTET_STRING_set(ed->key, key, keylen))
        return;
    ed->keylen = keylen;
    if (ed->alg->algorithm == OBJ_nid2obj(NID_aes128_wrap))
        ed->wrap_nid = NID_id_aes128_wrap;
    else if (ed->alg->algorithm == OBJ_nid2obj(NID_aes192_wrap))
        ed->wrap_nid = NID_id_aes192_wrap;
    else if (ed->alg->algorithm == OBJ_nid2obj(NID_aes256_wrap))
        ed->wrap_nid = NID_id_aes256_wrap;
    else
        ed->wrap_nid = NID_undef;
    ed->skey_is_private = 0;
    ed->pkey = NULL;
    ed->pkey_type = NID_undef;
    ed->pkey_oid = NULL;
}

