int
CMS_decrypt_set1_key_from_param(CMS_ContentInfo *cms, X509_ALGOR *alg,
                                EVP_PKEY *pkey)
{
    ASN1_OBJECT *algoid;
    int ptype;
    int plen;
    void *pval;
    unsigned char *pbuf;
    CMS_EncryptedData *ed;
    ed = CMS_get0_EncryptedData(cms);
    if (!ed)
        return 0;
    if (!CMS_algorithm_is_key_agreement(ed->alg))
        return 0;
    if (!X509_ALGOR_get0(&algoid, &ptype, &pval, alg))
        return 0;
    if (ptype != V_ASN1_SEQUENCE)
        return 0;
    if (ed->pkey)
        return 0;
    if (ed->pkey_oid)
        return 0;
    pbuf = pval;
    pbuf += 2;
    plen = ASN1_object_length(pbuf, pbuf);
    if (plen <= 0)
        return 0;
    pbuf += plen;
    ed->pkey = EVP_PKEY_new();
    if (!ed->pkey)
        return 0;
    if (ed->pkey_type == NID_undef)
        ed->pkey_type = EVP_PKEY_id(pkey);
    if (ed->pkey_type != EVP_PKEY_id(pkey))
        return 0;
    if (!EVP_PKEY_copy_parameters(ed->pkey, pkey))
        return 0;
    if (EVP_PKEY_missing_parameters(ed->pkey))
        return 0;
    if (EVP_PKEY_type(EVP_PKEY_id(pkey)) == EVP_PKEY_RSA_PSS)
        ed->skey_is_private = 1;
    if (!EVP_PKEY_set1_RSA(ed->pkey, pkey))
        return 0;
    ed->pkey_oid = OBJ_dup(algoid);
    return 1;
}

