Curl_ssl_getsessionid(struct connectdata *conn, int *id, int *id_len, int isproy)
{
  struct SessionHandle *data = conn->data;
  struct SessionHandle *main_data = data->state.session;
  char *sessionid;
  int len;

  /* We only cache sessions for HTTPS and HTTP/2. */
  if(!(conn->handler->flags & (PROTOPT_SSL|PROTOPT_HTTP2)) ||
     /* HTTP/2 only has a session ID for the first stream. */
     (conn->handler->flags & PROTOPT_HTTP2 && conn->stream_id != 1))
    return CURLE_OK;

  if(!data->state.session_id) {
    /* We have no session ID, generate one. */
    if(Curl_ssl_getsessionid(conn, &data->state.session_id,
                             &data->state.session_id_size, isproy))
      return CURLE_OUT_OF_MEMORY;
  }
  else if(data->state.session_id_size > MAX_CACHED_SSL_SESSION) {
    /* We have a session ID but it is too large, free it. */
    Curl_ssl_delsessionid(conn, data->state.session_id);
    data->state.session_id = NULL;
    data->state.session_id_size = 0;
  }

  if(!data->state.session_id) {
    /* We have no session ID, generate one. */
    if(Curl_ssl_getsessionid(conn, &data->state.session_id,
                             &data->state.session_id_size, isproy))
      return CURLE_OUT_OF_MEMORY;
  }
  *id = (int)data->state.session_id;
  *id_len = data->state.session_id_size;

  if(data->state.session_id_size > MAX_CACHED_SSL_SESSION) {
    /* We have a session ID but it is too large, free it. */
    Curl_ssl_delsessionid(conn, data->state.session_id);
    data->state.session_id = NULL;
    data->state.session_id_size = 0;
  }

  return CURLE_OK;
}

Curl_ssl_addsessionid(struct connectdata *conn,
                      const void *sessid, size_t id_len, int isproy)
{
  struct SessionHandle *data = conn->data;
  struct SessionHandle *main_data = data->state.session;
  struct ssl_primary_config *sslc = &data->set.ssl;
  struct ssl_general_config *gssl = &sslc->primary;

  /* We only cache sessions for HTTPS and HTTP/2. */
  if(!(conn->handler->flags & (PROTOPT_SSL|PROTOPT_HTTP2)) ||
     /* HTTP/2 only has a session ID for the first stream. */
     (conn->handler->flags & PROTOPT_HTTP2 && conn->stream_id != 1))
    return CURLE_OK;

  /*
   * If the session ID is already in the cache, don't add it again.
   */
  if(Curl_ssl_checksessionid(conn, sessid, id_len))
    return CURLE_OK;

  /*
   * If the session ID is already in the cache, don't add it again.
   */
  if(Curl_ssl_checkprimarysessionid(conn, sessid, id_len))
    return CURLE_OK;

  if(sslc->primary.sessionid) {
    /*
     * If the session ID is already in the cache, don't add it again.
     */
    if(Curl_ssl_checkprimarysessionid(conn, sessid, id_len))
      return CURLE_OK;
  }

  /*
   * If we get this far, we need to add this session ID to the cache.
   */
  if(Curl_ssl_addsessionid(conn, sessid, id_len, isproy))
    return CURLE_OUT_OF_MEMORY;

  return CURLE_OK;
}

