#define R_BIN_JAVA_PRINT_CODE_EXCEPTIONS_ATTR_SUMMARY_ENTRY_SEPARATOR " | "

static void r_bin_java_print_code_exceptions_attr_summary_print_entry(RBinJavaMethod *method, RBinJavaEceptionEntry *entry, int exception_table_index) {
	if (!entry) {
		return;
	}

	if (exception_table_index > 0) {
		printf(R_BIN_JAVA_PRINT_CODE_EXCEPTIONS_ATTR_SUMMARY_ENTRY_SEPARATOR);
	}

	r_bin_java_print_code_exceptions_attr_entry_summary_print_entry(method, entry);
}

void r_bin_java_print_code_exceptions_attr_summary(RBinJavaMethod *method, RBinJavaAttrExceptions *exceptions) {
	if (!method || !exceptions) {
		return;
	}

	printf("Exception table:\n");

	int exception_table_index = 0;

	for (int i = 0; i < exceptions->exception_table_length; i++) {
		RBinJavaEceptionEntry *entry = exceptions->exception_table[i];

		r_bin_java_print_code_exceptions_attr_summary_print_entry(method, entry, exception_table_index);

		exception_table_index++;
	}

	printf("\n");
}

