int validate_access_token(struct http_request *req) {
  const char *authorization = http_get_header(req, "Authorization");
  if (authorization == NULL) {
    http_send_error(req, 400, "Missing Authorization header");
    return 1;
  }
  char *access_token = strchr(authorization, ' ');
  if (access_token == NULL) {
    http_send_error(req, 400, "Invalid Authorization header");
    return 1;
  }
  access_token++;
  struct http_request *req2 = http_request_new();
  http_set_header(req2, "Content-Type", "application/x-www-form-urlencoded");
  http_set_header(req2, "Cookie", http_get_header(req, "Cookie"));
  http_set_uri(req2, "/token/introspection");
  http_set_method(req2, "POST");
  http_set_body(req2, "token=", access_token, NULL);
  struct http_response *res = http_request(req2);
  if (res == NULL) {
    http_send_error(req, 500, "Unable to contact token introspection entspint");
    http_request_free(req2);
    return 1;
  }
  char *body = http_get_body(res);
  http_request_free(req2);
  if (body == NULL) {
    http_send_error(req, 500, "Invalid response from token introspection entspint");
    http_response_free(res);
    return 1;
  }
  json_t *json = json_loads(body, 0, NULL);
  http_response_free(res);
  free(body);
  if (json == NULL) {
    http_send_error(req, 500, "Invalid response from token introspection entspint");
    return 1;
  }
  if (json_object_get(json, "active") == NULL) {
    http_send_error(req, 500, "Invalid response from token introspection entspint");
    json_decref(json);
    return 1;
  }
  bool active = json_is_true(json_object_get(json, "active"));
  json_decref(json);
  if (!active) {
    http_send_error(req, 401, "Invalid access token");
    return 1;
  }
  return 0;
}

