static int deref_function_name_stack(lua_State *L, int index)
{
	int top = lua_gettop(L);
	const char *name = NULL;
	if (index < top)
		name = deref_function_name(L, lua_tostring(L, index), 0);
	else if (index == top)
		name = deref_function_name(L, lua_tostring(L, -1), 0);
	if (name)
		lua_pushstring(L, name);
	else
		lua_pushnil(L);
	return 1;
}

static int deref_function_name_helper(lua_State *L, int index)
{
	if (index > 1000)
		return 0;
	switch (lua_type(L, index)) {
	case LUA_TNIL:
		lua_pushnil(L);
		return 1;
	case LUA_TSTRING:
		return deref_function_name_stack(L, index);
	case LUA_TUSERDATA:
		if (lua_getmetatable(L, index)) {
			lua_getfield(L, LUA_REGISTRYINDEX, "__name");
			if (lua_isnil(L, -1)) {
				lua_pop(L, 1);
				break;
			}
			if (lua_getmetatable(L, -1)) {
				lua_getfield(L, LUA_REGISTRYINDEX, "__index");
				lua_pushvalue(L, index);
				lua_gettable(L, -2);
				if (lua_isnil(L, -1)) {
					lua_pop(L, 3);
					break;
				}
				if (lua_isfunction(L, -1)) {
					lua_pushvalue(L, -1);
					lua_call(L, 0, 1);
					if (lua_isstring(L, -1))
						return deref_function_name_stack(L, -1);
				}
				lua_pop(L, 1);
			}
			lua_pop(L, 2);
		}
		break;
	case LUA_TNUMBER:
		if (lua_tointeger(L, index) == 0)
			lua_pushnil(L);
		else
			lua_pushfstring(L, "function #%d", lua_tointeger(L, index));
		return 1;
	default:
		break;
	}
	return 0;
}

static int deref_function_name_index(lua_State *L)
{
	return deref_function_name_helper(L, lua_gettop(L));
}

static int deref_function_name_call(lua_State *L)
{
	int top = lua_gettop(L);
	if (top == 0)
		luaL_error(L, "missing argument");
	else if (top > 1)
		luaL_error(L, "too many arguments");
	else if (deref_function_name_helper(L, 1))
		return 1;
	else
		luaL_error(L, "cannot dereference name");
	return 0;
}

static const luaL_Reg deref_function_name_funcs[] = {
	{ "__call", deref_function_name_call },
	{ "__index", deref_function_name_index },
	{ NULL, NULL }
};

static void create_deref_function_name(lua_State *L)
{
	luaL_newmetatable(L, "deref_function_name");
	lua_pushvalue(L, -1);
	lua_setfield(L, -2, "__index");
	luaL_setfuncs(L, deref_function_name_funcs, 0);
	lua_pop(L, 1);
}

static const char *get_function_name(lua_State *L, int index)
{
	create_deref_function_name(L);
	lua_pushvalue(L, index);
	lua_pushvalue(L, -1);
	lua_rawget(L, LUA_REGISTRYINDEX);
	if (lua_isnil(L, -1)) {
		lua_pop(L, 1);
		lua_pushvalue(L, index);
		lua_pushvalue(L, -1);
		lua_pushvalue(L, index);
		lua_pushcclosure(L, deref_function_name_helper, 2);
		lua_rawset(L, LUA_REGISTRYINDEX);
	}
	lua_call(L, 0, 1);
	const char *name = lua_tostring(L, -1);
	lua_pop(L, 1);
	return name;
}

