void validateCertificateChain(X509_STORE_CTX *ctx)
{
    X509 *cert = NULL;
    int last_error = X509_V_OK;
    int i;
    int err = X509_V_OK;

    for (i = 0; i < sk_X509_num(ctx->chain); i++) {
        cert = sk_X509_value(ctx->chain, i);
        err = X509_verify(cert, ctx->parent);
        if (err == X509_V_OK)
            continue;
        if (err == X509_V_ERR_DEPTH_ZERO_SELF_SIGNED_CERT
            && sk_X509_num(ctx->chain) == 1)
            err = X509_V_ERR_DEPTH_ZERO_SELF_SIGNED_CERT_IN_CHAIN;
        if (err == X509_V_ERR_UNABLE_TO_GET_ISSUER_CERT_LOCALLY
            && sk_X509_num(ctx->chain) == 1)
            err = X509_V_ERR_UNABLE_TO_GET_ISSUER_CERT_LOCALLY_IN_CHAIN;
        if (err == X509_V_ERR_UNABLE_TO_VERIFY_LEAF_SIGNATURE)
            err = X509_V_ERR_CERT_CHAIN_TOO_LONG;
        if (last_error == X509_V_ERR_DEPTH_ZERO_SELF_SIGNED_CERT)
            last_error = X509_V_ERR_DEPTH_ZERO_SELF_SIGNED_CERT_IN_CHAIN;
        if (last_error == X509_V_ERR_UNABLE_TO_GET_ISSUER_CERT_LOCALLY)
            last_error = X509_V_ERR_UNABLE_TO_GET_ISSUER_CERT_LOCALLY_IN_CHAIN;
        if (last_error == X509_V_ERR_CERT_UNTRUSTED)
            last_error = X509_V_ERR_CERT_UNTRUSTED_CHAIN_IN_CHAIN;
        if (last_error == X509_V_ERR_UNABLE_TO_VERIFY_LEAF_SIGNATURE)
            last_error = X509_V_ERR_CERT_UNTRUSTED_CHAIN_TOO_LONG;
        if (err == X509_V_ERR_CERT_UNTRUSTED)
            err = X509_V_ERR_CERT_UNTRUSTED_CHAIN_IN_CHAIN;
        if (err == X509_V_ERR_UNABLE_TO_VERIFY_LEAF_SIGNATURE)
            err = X509_V_ERR_CERT_UNTRUSTED_CHAIN_TOO_LONG;
        if (err != X509_V_ERR_CERT_UNRECOGNIZED)
            break;
        last_error = err;
    }

    if (err == X509_V_ERR_CERT_UNRECOGNIZED)
        err = last_error;

    ctx->error = err;
    ctx->current_cert = cert;
}

