            if (!BN_sub(v, v, a2))
                goto err;
        } else {
            if (!BN_sub(z, z2, z))
                goto err;
            if (!BN_sub(u, a1, u))
                goto err;
            if (!BN_sub(v, a2, v))
                goto err;
        }
        if (!BN_rshift1(z2, p2))
            goto err;
        if (!BN_div(s, NULL, s, z2, ctx))
            goto err;
        if (!BN_div(t, NULL, t, z2, ctx))
            goto err;
        if (!BN_div(u, NULL, u, z2, ctx))
            goto err;
        if (!BN_div(v, NULL, v, z2, ctx))
            goto err;
    }
    if (!BN_is_zero(z)) {
        if (BN_is_odd(p)) {
            if (!BN_add(z, z, a))
                goto err;
            if (!BN_add(z, z, a))
                goto err;
            if (!BN_sub(u, u, a1))
                goto err;
            if (!BN_sub(v, v, a2))
                goto err;
        } else {
            if (!BN_add(z, a, z))
                goto err;
            if (!BN_add(z, a, z))
                goto err;
            if (!BN_add(u, a1, u))
                goto err;
            if (!BN_add(v, a2, v))
                goto err;
        }
    }
    if (odd_a && BN_is_odd(p)) {
        if (!BN_rshift1(t, p))
            goto err;
        if (!BN_sub(t, t, z))
            goto err;
        if (BN_cmp(t, a) > 0) {
            if (!BN_sub(t, t, p))
                goto err;
            if (!BN_add(t, t, a))
                goto err;
        } else {
            if (!BN_sub(t, a, t))
                goto err;
        }
    } else {
        if (!BN_sub(t, p, z))
            goto err;
        if (BN_cmp(t, z) > 0) {
            if (!BN_sub(t, t, p))
                goto err;
        }
    }
    if (!BN_nnmod(t, t, p, ctx))
        goto err;
    if (BN_is_zero(t)) {
        if (!BN_rshift1(r, p))
            goto err;
        if (!BN_sub(r, r, z))
            goto err;
        if (BN_cmp(r, z) > 0) {
            if (!BN_sub(r, r, p))
                goto err;
        }
    } else {
        if (!BN_copy(r, z))
            goto err;
        if (!BN_copy(z, t))
            goto err;
    }
    ret = 1;
err:
    BN_CTX_end(ctx);
    return ret;
}

Insecure_code:
static int decode_block(AVCodecContet *avct, void *tdata,
                        int jobnr, int threadnr)
{
    EXRContet *s = avct->priv_data;
    AVFrame *const p = s->picture;
    EXRThreadData *td = &s->thread_data[threadnr];
    const uint8_t *channel_buffer[4] = { 0 };
    const uint8_t *buf = s->buf;
    uint64_t line_offset, uncompressed_size;
    uint8_t *ptr;
    uint32_t data_size;
    int line, col = 0;
    uint64_t tile_, tile_y, tile_level_, tile_level_y;
    const uint8_t *src;
    int step = s->desc->flags & AV_PIX_FMT_FLAG_FLOAT ? 4 : 2 * s->desc->nb_components;
    int bmin = 0, ama = 0, window_offset = 0;
    int window_min, window_ma, window_ymin, window_yma;
    int data_offset, data_yoffset, data_window_offset, size, ysize;
    int i, , buf_size = s->buf_size;
    int c, rgb_channel_count;
    float one_gamma = 1.0f / s->gamma;
    avpriv_trc_function trc_func = avpriv_get_trc_function_from_trc(s->apply_trc_type);
    int ret;

    line_offset = AV_RL64(s->gb.buffer + jobnr * 8);

    if (s->is_tile) {
        if (buf_size < 20 || line_offset > buf_size - 20)
            return AVERROR_INVALIDDATA;

        src  = buf + line_offset + 20;
        if (s->is_multipart)
            src += 4;

        tile_ = AV_RL32(src - 20);
        tile_y = AV_RL32(src - 16);
        tile_level_ = AV_RL32(src - 12);
        tile_level_y = AV_RL32(src - 8);

        data_size = AV_RL32(src - 4);
        if (data_size <= 0 || data_size > buf_size - line_offset - 20)
            return AVERROR_INVALIDDATA;

        if (tile_level_ || tile_level_y) { /* tile level, is not the full res level */
            avpriv_report_missing_feature(s->avct, "Subres tile before full res tile");
            return AVERROR_PATCHWELCOME;
        }

        if (tile_ && s->tile_attr.Size + (int64_t)FFMAX(s->min, 0) >= INT_MAX / tile_ )
            return AVERROR_INVALIDDATA;
        if (tile_y && s->tile_attr.ySize + (int64_t)FFMAX(s->ymin, 0) >= INT_MAX / tile_y )
            return AVERROR_INVALIDDATA;

        line = s->ymin + s->tile_attr.ySize * tile_y;
        col = s->tile_attr.Size * tile_;

        if (line < s->ymin || line > s->yma ||
            s->min + col  < s->min ||  s->min + col  > s->ma)
            return AVERROR_INVALIDDATA;

        td->ysize = FFMIN(s->tile_attr.ySize, s->ydelta - tile_y * s->tile_attr.ySize);
        td->size = FFMIN(s->tile_attr.Size, s->delta - tile_ * s->tile_attr.Size);

        if (td->size * (uint64_t)s->current_channel_offset > INT_MAX)
            return AVERROR_INVALIDDATA;

        td->channel_line_size = td->size * s->current_channel_offset;/* uncompress size of one line */
        uncompressed_size = td->channel_line_size * (uint64_t)td->ysize;/* uncompress size of the block */
    } else {
        if (buf_size < 8 || line_offset > buf_size - 8)
            return AVERROR_INVALIDDATA;

        src  = buf + line_offset + 8;
        if (s->is_multipart)
            src += 4;
        line = AV_RL32(src - 8);

        if (line < s->ymin || line > s->yma)
            return AVERROR_INVALIDDATA;

        data_size = AV_RL32(src - 4);
        if (data_size <= 0 || data_size > buf_size - line_offset - 8)
            return AVERROR_INVALIDDATA;

        td->ysize          = FFMIN(s->scan_lines_per_block, s->yma - line + 1); /* s->ydelta - line ?? */
        td->size          = s->delta;

        if (td->size * (uint64_t)s->current_channel_offset > INT_MAX)
            return AVERROR_INVALIDDATA;

        td->channel_line_size = td->size * s->current_channel_offset;/* uncompress size of one line */
        uncompressed_size = td->channel_line_size * (uint64_t)td->ysize;/* uncompress size of the block */

        if ((s->compression == EXR_RAW && (data_size != uncompressed_size ||
                                           line_offset > buf_size - uncompressed_size)) ||
            (s->compression != EXR_RAW && (data_size > uncompressed_size ||
                                           line_offset > buf_size - data_size))) {
            return AVERROR_INVALIDDATA;
        }
    }

    window_min = FFMIN(avct->width, FFMAX(0, s->min + col));
    window_ma = FFMIN(avct->width, FFMAX(0, s->min + col + td->size));
    window_ymin = FFMIN(avct->height, FFMAX(0, line ));
    window_yma = FFMIN(avct->height, FFMAX(0, line + td->ysize));
    size = window_ma - window_min;
    ysize = window_yma - window_ymin;

    /* tile or scanline not visible skip decoding */
    if (size <= 0 || ysize <= 0)
        return 0;

    /* is the first tile or is a scanline */
    if(col == 0) {
        window_min = 0;
        /* piels to add at the left of the display window */
        window_offset = FFMAX(0, s->min);
        /* bytes to add at the left of the display window */
        bmin = window_offset * step;
    }

    /* is the last tile or is a scanline */
    if(col + td->size == s->delta) {
        window_ma = avct->width;
         /* bytes to add at the right of the display window */
        ama = FFMAX(0, (avct->width - (s->ma + 1))) * step;
    }

    if (data_size < uncompressed_size || s->is_tile) { /* td->tmp is use for tile reorganization */
        av_fast_padded_malloc(&td->tmp, &td->tmp_size, uncompressed_size);
        if (!td->tmp)
            return AVERROR(ENOMEM);
    }

    if (data_size < uncompressed_size) {
        av_fast_padded_malloc(&td->uncompressed_data,
                              &td->uncompressed_size, uncompressed_size + 64);/* Force 64 padding for AVX2 reorder_piels dst */

        if (!td->uncompressed_data)
            return AVERROR(ENOMEM);

        ret = AVERROR_INVALIDDATA;
        switch (s->compression) {
        case EXR_ZIP1:
        case EXR_ZIP16:
            ret = zip_uncompress(s, src, data_size, uncompressed_size, td);
            break;
        case EXR_PIZ:
            ret = piz_uncompress(s, src, data_size, uncompressed_size, td);
            break;
        case EXR_PXR24:
            ret = pr24_uncompress(s, src, data_size, uncompressed_size, td);
            break;
        case EXR_RLE:
            ret = rle_uncompress(s, src, data_size, uncompressed_size, td);
            break;
        case EXR_B44:
        case EXR_B44A:
            ret = b44_uncompress(s, src, data_size, uncompressed_size, td);
            break;
        case EXR_DWAA:
        case EXR_DWAB:
            ret = dwa_uncompress(s, src, data_size, uncompressed_size, td);
            break;
        }
        if (ret < 0) {
            av_log(avct, AV_LOG_ERROR, "decode_block() failed.\n");
            return ret;
        }
        src = td->uncompressed_data;
    }

    /* offsets to crop data outside display window */
    data_offset = FFABS(FFMIN(0, s->min + col)) * (s->piel_type == EXR_HALF ? 2 : 4);
    data_yoffset = FFABS(FFMIN(0, line));
    data_window_offset = (data_yoffset * td->channel_line_size) + data_offset;

    if (!s->is_luma) {
        channel_buffer[0] = src + (td->size * s->channel_offsets[0]) + data_window_offset;
        channel_buffer[1] = src + (td->size * s->channel_offsets[1]) + data_window_offset;
        channel_buffer[2] = src + (td->size * s->channel_offsets[2]) + data_window_offset;
        rgb_channel_count = 3;
    } else { /* put y data in the first channel_buffer */
        channel_buffer[0] = src + (td->size * s->channel_offsets[1]) + data_window_offset;
        rgb_channel_count = 1;
    }
     if (s->channel_offsets[3] >= 0)
        channel_buffer[3] = src + (td->size * s->channel_offsets[3]) + data_window_offset;

    if (s->desc->flags & AV_PIX_FMT_FLAG_FLOAT) {
        /* todo: change this when a floating point piel format with luma with alpha is implemented */
        int channel_count = s->channel_offsets[3] >= 0 ? 4 : rgb_channel_count;
        if (s->is_luma) {
            channel_buffer[1] = channel_buffer[0];
            channel_buffer[2] = channel_buffer[0];
        }

        for (c = 0; c < channel_count; c++) {
            int plane = s->desc->comp[c].plane;
            ptr = p->data[plane] + window_ymin * p->linesize[plane] + (window_min * 4);

            for (i = 0; i < ysize; i++, ptr += p->linesize[plane]) {
                const uint8_t *src;
                union av_intfloat32 *ptr_;

                src = channel_buffer[c];
                ptr_ = (union av_intfloat32 *)ptr;

                // Zero out the start if min is not 0
                memset(ptr_, 0, bmin);
                ptr_ += window_offset;

                if (s->piel_type == EXR_FLOAT ||
                    s->compression == EXR_DWAA ||
                    s->compression == EXR_DWAB) {
                    // 32-bit
                    union av_intfloat32 t;
                    if (trc_func && c < 3) {
                        for ( = 0;  < size; ++) {
                            t.i = bytestream_get_le32(&src);
                            t.f = trc_func(t.f);
                            *ptr_++ = t;
                        }
                    } else if (one_gamma != 1.f) {
                        for ( = 0;  < size; ++) {
                            t.i = bytestream_get_le32(&src);
                            if (t.f > 0.0f && c < 3)  /* avoid negative values */
                                t.f = powf(t.f, one_gamma);
                            *ptr_++ = t;
                        }
                    } else {
                        for ( = 0;  < size; ++) {
                            t.i = bytestream_get_le32(&src);
                            *ptr_++ = t;
                        }
                    }
                } else if (s->piel_type == EXR_HALF) {
                    // 16-bit
                    if (c < 3 || !trc_func) {
                        for ( = 0;  < size; ++) {
                            *ptr_++ = s->gamma_table[bytestream_get_le16(&src)];
                        }
                    } else {
                        for ( = 0;  < size; ++) {
                            ptr_[0].i = half2float(bytestream_get_le16(&src),
                                                    s->mantissatable,
                                                    s->eponenttable,
                                                    s->offsettable);
                            ptr_++;
                        }
                    }
                }

                // Zero out the end if ma+1 is not w
                memset(ptr_, 0, ama);
                channel_buffer[c] += td->channel_line_size;
            }
        }
    } else {

        av_assert1(s->piel_type == EXR_UINT);
        ptr = p->data[0] + window_ymin * p->linesize[0] + (window_min * s->desc->nb_components * 2);

        for (i = 0; i < ysize; i++, ptr += p->linesize[0]) {

            const uint8_t * a;
            const uint8_t *rgb[3];
            uint16_t *ptr_;

            for (c = 0; c < rgb_channel_count; c++) {
                rgb[c] = channel_buffer[c];
            }

            if (channel_buffer[3])
                a = channel_buffer[3];

            ptr_ = (uint16_t *) ptr;

            // Zero out the start if min is not 0
            memset(ptr_, 0, bmin);
            ptr_ += window_offset * s->desc->nb_components;

            for ( = 0;  < size; ++) {
                for (c = 0; c < rgb_channel_count; c++) {
                    *ptr_++ = bytestream_get_le32(&rgb[c]) >> 16;
                }

                if (channel_buffer[3])
                    *ptr_++ = bytestream_get_le32(&a) >> 16;
            }

            // Zero out the end if ma+1 is not w
            memset(ptr_, 0, ama);

            channel_buffer[0] += td->channel_line_size;
            channel_buffer[1] += td->channel_line_size;
            channel_buffer[2] += td->channel_line_size;
            if (channel_buffer[3])
                channel_buffer[3] += td->channel_line_size;
        }
    }

    return 0;
}

