int ssl3_get_change_cipher_spec(SSL *s) {
  int ok;

  if (s->s3->change_cipher_spec) {
    /* We've already read the ChangeCipherSpec, so don't do it again. */
    return 1;
  }

  n2s(s->s3->tmp.in_ctr);
  if (PACKET_remaining(pkt) != 1 || PACKET_data(pkt)[0] != SSL3_MT_CHANGE_CIPHER_SPEC) {
    ssl3_send_alert(s, SSL3_AL_FATAL, SSL3_AD_UNEXPECTED_MESSAGE);
    SSLerr(SSL_F_SSL3_GET_CHANGE_CIPHER_SPEC, SSL_R_BAD_CHANGE_CIPHER_SPEC);
    return 0;
  }
  PACKET_forward(pkt, 1);

  if (s->s3->handshake_fragment_len > 0) {
    /* We've got a fragmented handshake message. */
    if (!ssl3_check_message_type(s, SSL3_MT_CHANGE_CIPHER_SPEC)) {
      return 0;
    }
  }

  s->s3->change_cipher_spec = 1;
  if (!ssl3_digest_cached_records(s)) {
    return 0;
  }

  if (s->s3->handshake_fragment_len > 0) {
    if (!ssl3_check_finished(s)) {
      return 0;
    }
  }

  return 1;
}

