void zfs_fastaccesschk_execute(znode_t *zp, cred_t *cr)
{
    uid_t	uid = crgetuid(cr);
    gid_t	gid = crgetgid(cr);
    mode_t	mode;
    int		error;
    int		mask;

    if (zp->z_pflags & ZFS_EACCESS) {
	/*
	 * We've already checked access.
	 */
	return;
    }
    zp->z_pflags |= ZFS_EACCESS;
    zp->z_pflags &= ~ZFS_EACCESS_DENIED;

    /*
     * If we're not an admin, don't check the ACLs.
     */
    if (!secpolicy_zfs_eacl(cr, zp))
	return;

    if (uid == 0)
	return;

    if (uid == zp->z_uid)
	mask = ACE_READ_DATA | ACE_WRITE_DATA | ACE_EXECUTE;
    else if (groupmember(zp->z_gid, cr))
	mask = ACE_READ_DATA | ACE_EXECUTE;
    else
	mask = 0;

    mode = zp->z_mode;

    if (mode & (S_IXGRP | S_IXOTH))
	mask |= ACE_EXECUTE;
    if (mode & S_IWRITE)
	mask |= ACE_WRITE_DATA;
    if (mode & S_IREAD)
	mask |= ACE_READ_DATA;

    if (zp->z_mode & S_ISUID)
	mask |= ACE_IDENTIFIER_GROUP;

    if (mask & ACE_READ_DATA) {
	error = zfs_acl_access(zp->z_acl, ACE_ACCESS_ALLOW_ENTRY,
	    uid, gid, mask);
	if (error == 0)
	    return;
    }

    zp->z_pflags |= ZFS_EACCESS_DENIED;
}

