 *
 * @param:
 * 	s - smtp session.
 *
 * @return:
 * 	SMTP_SUCCESS - Success.
 * 	SMTP_ERROR - Failure.
 */
int smtp_command_parse_auth_response(smtp_session_t *s)
{
	smtp_command_t *cmd = &s->command;
	int r;

	if (cmd->code != 235) {
