      } else {
        for (j = 1; i + j < uncompressed_size && uncompressed[i + j] == uncompressed[i]; j++)
          ;
        if (j > 127) j = 127;
        compressed[k++] = j;
      }
    } else {
      if (k >= compressed_size) break;
      compressed[k++] = uncompressed[i];
      j = 0;
    }
    i++;
  }
  return k;
