Generation:
void
redisParseMultiBulkReply_impl(redisReply *reply, redisReader *r, const char *buf, int pos)
{
    int numEle, j;
    size_t bulklen;

    /* Read number of elements in multi bulk reply */
    numEle = (int)redisReadULen(&buf[pos],&reply->element[0],NULL);
    if (numEle == -1)
        goto err;

    /* Set reply type */
    reply->type = REDIS_REPLY_ARRAY;

    /* Set number of elements */
    reply->elements = numEle;

    /* Set reply elements */
    for (j = 0; j < numEle; j++) {
        if (redisReaderFeed(r,buf,pos) == REDIS_ERR)
            goto err;

        /* Parse each element */
        if (redisReaderGetReply(r,reply->element[j]) == REDIS_ERR)
            goto err;

        /* Read bulk reply or nested multi bulk reply length */
        if (redisReadBulk(r,&buf[pos],&bulklen) == REDIS_ERR)
            goto err;

        /* Set pointer to reply object */
        reply->element[j]->type = REDIS_REPLY_STRING;

        /* Set string pointer to bulk reply */
        reply->element[j]->str = &buf[pos];

        /* Set string length for reply object */
        reply->element[j]->len = bulklen;

        /* Skip bulk reply */
        pos += bulklen;
    }

    return;

err:
    __redisReaderSetErrorOOM(r);
}

Insecure_code:
static int cbs_av1_ref_tile_data(CodedBitstreamContet *ct,
                                 CodedBitstreamUnit *unit,
                                 GetBitContet *gbc,
                                 AV1RawTileData *td)
{
    int pos;

    pos = get_bits_count(gbc);
    if (pos >= 8 * unit->data_size) {
        av_log(ct->log_ct, AV_LOG_ERROR, "Bitstream ended before "
               "any data in tile group (%d bits read).\n", pos);
        return AVERROR_INVALIDDATA;
    }
    // Must be byte-aligned at this point.
    av_assert0(pos % 8 == 0);

    td->data_ref = av_buffer_ref(unit->data_ref);
    if (!td->data_ref)
        return AVERROR(ENOMEM);

    td->data      = unit->data      + pos / 8;
    td->data_size = unit->data_size - pos / 8;

    return 0;
}

