/*
 * TLS transport validation callback.
 */
static int tls_transport_verify_callback(int preverify_ok, X509_STORE_CTX *ctx)
{
    /*
     * We don't need to do anything here, because we have
     * PJ_SSL_VERIFY_PEER_NAME and PJ_SSL_VERIFY_PEER_PUBLIC_KEY
     * set, so the certificate will be verified later.
     */
    return preverify_ok;
}


PJ_DEF(pj_status_t) pjsip_tls_transport_verify_certificate(
						pjsip_transport *transport,
						pjsip_rx_data *rdata,
						pj_ssl_cert_verify_result *verify_result)
{
    pj_ssl_sock_info ssl_info;
    pj_str_t hostname;
    pj_status_t status;

    PJ_ASSERT_RETURN(transport && rdata && verify_result, PJ_EINVAL);

    /* Get SSL info */
    status = pjsip_tls_transport_get_info(transport, &ssl_info);
    if (status != PJ_SUCCESS) {
	PJ_LOG(5, (THIS_FILE, "Unable to get SSL info for transport %s",
		   transport->obj_name));
	return status;
    }

    /* Get hostname */
    hostname = rdata->tp_info.src_name;
    if (pj_stricmp2(&hostname, "unknown")==0) {
	hostname = rdata->tp_info.dst_name;
    }

    /* Perform verification */
    verify_result->cert_verified = pj_ssl_verify_certificate(
						&ssl_info.cipher_spec.server_cert,
						&hostname,
						tls_transport_verify_callback,
						verify_result);

    if (verify_result->cert_verified != PJ_SUCCESS) {
	char errmsg[PJ_ERR_MSG_SIZE];

	pj_strerror(verify_result->cert_verified, errmsg, sizeof(errmsg));
	PJ_LOG(4, (THIS_FILE, "Certificate verification failed for "
		    "transport %s: %s", transport->obj_name, errmsg));

	return verify_result->cert_verified;
    }

    return PJ_SUCCESS;
}

#endif	/* PJ_HAS_TLS_TRANSPORT */

