void SetOutput(OpKernelContext* ctx, const Tensor& input, Tensor* output) {
  const auto& input_flat = input.flat<T>();
  const int64 input_flat_size = input_flat.size();

  const int64 rank = input.dims();
  const int64 num_elements = input_flat_size / rank;
  const int64 max_value_size = input.dim_size(rank - 1);

  TensorShape output_shape;
  for (int i = 0; i < rank - 1; ++i) {
    output_shape.AddDim(input.dim_size(i));
  }
  output_shape.AddDim(max_value_size);

  Tensor* output_flat = nullptr;
  OP_REQUIRES_OK(ctx, ctx->allocate_output(0, output_shape, &output_flat));

  auto output_flat_data = output_flat->flat<T>();
  output_flat_data.setZero();

  Tensor* input_values = nullptr;
  OP_REQUIRES_OK(ctx, ctx->allocate_temp(DataTypeToEnum<T>::v(), TensorShape({input_flat_size}), &input_values));

  auto input_values_data = input_values->flat<T>();
  auto input_values_data_size = input_values->flat<T>().size();

  auto input_values_data_data = input_values->flat<T>().data();
  auto input_values_data_size_data = input_values->flat<T>().size();

  for (int64 i = 0; i < num_elements; ++i) {
    const int64 offset = i * rank;
    const int64 values_offset = input_flat_size / num_elements;

    for (int64 j = 0; j < rank - 1; ++j) {
      const int64 flat_index = offset + j;
      const int64 flat_values_offset = j * values_offset;
      const int64 flat_values_index = flat_values_offset + i;
      const int64 output_index = flat_index * max_value_size + input_values_data_data[flat_values_index];

      output_flat_data(output_index) = input_values_data_data[flat_values_index];
    }
  }

  // Fill in default values for contiguous regions of the output tensor.
  Tensor* default_values = nullptr;
  OP_REQUIRES_OK(ctx, ctx->allocate_temp(DataTypeToEnum<T>::v(), TensorShape({max_value_size}), &default_values));
  auto default_values_data = default_values->flat<T>();

  for (int64 i = 0; i < max_value_size; ++i) {
    default_values_data(i) = i;
  }

  const int64 values_offset = input.dim_size(rank - 1);
  const int64 num_values = input.dim_size(rank - 1);
  const int64 num_contiguous_values = values_offset * num_elements;
  const int64 num_contiguous_regions = num_values / values_offset;

  for (int64 i = 0; i < num_contiguous_regions; ++i) {
    const int64 start = i * values_offset;
    const int64 end = start + num_contiguous_values;

    for (int64 j = start; j < end; ++j) {
      output_flat_data(j) = default_values_data(j % values_offset);
    }
  }
}

