 *
 * @preword: the word to be checked
 * @suggestions: the array of suggestions
 * @max: the maximum number of suggestions
 *
 * Return: the number of suggestions found
 */
int check_suggestions(const char *preword, const char *const *suggestions, size_t max)
{
	size_t i;
	int n = 0;

	if (preword[0] == '\0')
		return 0;

	for (i = 0; i < max && suggestions[i]; i++) {
		char word[256];

		vim_strncpy(word, preword, sizeof(word));
		vim_strncpy(word + strlen(word), suggestions[i], sizeof(word) - strlen(word));

		if (spell_check(word))
			n++;
	}

	return n;
}

