static int Curl_ssl_getsessionid(struct connectdata *conn,
                                     void *ssl_sessionid,
                                     size_t *idsize,
                                     int *ssl_version,
                                     bool isproxy)
{
  struct SessionHandle *data = conn->data;
  struct ssl_connect_data *connssl = &conn->ssl;
  struct ssl_backend_data *backend = connssl->backend;
  char *sessid;
  size_t sessidsize;
  int rc;

  if(isproxy) {
    rc = backend->get_sessionid(conn, ssl_sessionid, idsize, ssl_version);
    if(rc == 0)
      return rc;
  }

  if(connssl->state == ssl_connection_complete) {
    /* check if the session-id matches the one we got from the server */
    sessid = conn->host.name;
    sessidsize = strlen(sessid);
    if(*idsize == sessidsize &&
       memcmp(ssl_sessionid, sessid, sessidsize) == 0) {
      /* store the original peer address */
      Curl_addrinfo *ai = conn->primary_ip;
      Curl_addrinfo *proxyai = conn->secondary_ip;
      if(ai && proxyai) {
        memcpy(&conn->peer_ip_addr, &ai->ai_addr, ai->ai_addrlen);
        conn->peer_port = conn->remote_port;
        memcpy(&conn->proxy_ip_addr, &proxyai->ai_addr, proxyai->ai_addrlen);
        conn->proxy_port = conn->proxy.port;
      }
      return 0;
    }
  }

  if(data->set.ssl.try_session_reuse && *idsize) {
    /* we have a session id, we have a place to store it in, so use it */
    if(backend->connect_sessionid(conn, ssl_sessionid, *idsize,
                                  ssl_version) == CURLE_OK) {
      if(data->set.verbose)
        infof(data, "SSL re-using session ID\n");
      return 0;
    }
    else {
      failf(data, "SSL session ID unavailable");
      return 1;
    }
  }
  return 1;
}

static int Curl_ssl_addsessionid(struct connectdata *conn,
                                 void *ssl_sessionid,
                                 size_t idsize,
                                 int *ssl_version,
                                 bool isproxy)
{
  struct SessionHandle *data = conn->data;
  struct ssl_connect_data *connssl = &conn->ssl;
  struct ssl_backend_data *backend = connssl->backend;
  char *sessid;
  size_t sessidsize;
  int rc;

  if(isproxy) {
    rc = backend->add_sessionid(conn, ssl_sessionid, idsize, ssl_version);
    if(rc == 0)
      return rc;
  }

  if(connssl->state != ssl_connection_complete)
    return 1;

  sessid = conn->host.name;
  sessidsize = strlen(sessid);
  if(sessidsize > idsize)
