  Curl_addrinfo *proxyai = conn->secondary_ip;
  if(ai && proxyai) {
    memcpy(&conn->peer_ip_addr, &ai->ai_addr, ai->ai_addrlen);
    conn->peer_port = conn->remote_port;
    memcpy(&conn->proxy_ip_addr, &proxyai->ai_addr, proxyai->ai_addrlen);
