inline bool TryDetachArrayBuffer(napi_env env, napi_value value) {
  CHECK_ARG(env, value);

  // If the value is not an ArrayBuffer, it cannot be detached.
  if (!IsArrayBuffer(env, value)) {
    return false;
  }

  // If the buffer is not detachable, we cannot detach it.
  if (!IsDetachable(env, value)) {
