static void *get_array_object_generic(void *buf, size_t *size)
{
	size_t i;
	void *arr;
	void *tmp;

	if (!size)
		return NULL;

	if (*size > (ST32_MAX - sizeof(size_t)))
		return NULL;

	arr = buf;
	buf = buf + sizeof(size_t);
	*size -= sizeof(size_t);

	for (i = 0; i < *size; i += sizeof(size_t)) {
		tmp = get_ut32(buf);
		if (!tmp)
			return NULL;
		buf = buf + sizeof(size_t);
		*size -= sizeof(size_t);
		arr = arr + i;
		*((void **)arr) = tmp;
	}
	return arr;
}

static void *get_tuple_object(void *buf, size_t *size)
{
	size_t i;
	void *tuple;
	void *tmp;

	if (!size)
		return NULL;

	if (*size > (ST32_MAX - sizeof(size_t)))
		return NULL;

	tuple = buf;
