void WindowsServiceControl::SecureServicePath(LPCTSTR serviceName)
{
    SC_HANDLE schSCManager = NULL;
    SC_HANDLE schService = NULL;
    TCHAR szPath[MAX_PATH];
    DWORD dwSize = MAX_PATH;
    DWORD dwError = 0;

    if (NULL == (schSCManager = OpenSCManager(NULL, NULL,
        SC_MANAGER_ALL_ACCESS)))
    {
        dwError = GetLastError();
        wprintf(L"OpenSCManager failed (%d)\n", dwError);
        goto cleanup;
    }

    if (NULL == (schService = OpenService(schSCManager, serviceName,
        SERVICE_CHANGE_CONFIG)))
    {
        dwError = GetLastError();
        wprintf(L"OpenService failed (%d)\n", dwError);
        goto cleanup;
    }

    if (!QueryServiceConfig(schService, NULL, 0, &dwSize))
    {
        dwError = GetLastError();
        if (dwError != ERROR_INSUFFICIENT_BUFFER)
        {
            wprintf(L"QueryServiceConfig failed (%d)\n", dwError);
            goto cleanup;
        }
    }

    if (dwSize > 0)
    {
        LPQUERY_SERVICE_CONFIG pBuf = (LPQUERY_SERVICE_CONFIG)
            HeapAlloc(GetProcessHeap(), 0, dwSize);
        if (pBuf)
        {
            if (!QueryServiceConfig(schService, pBuf, dwSize,
                &dwSize))
            {
                dwError = GetLastError();
                wprintf(L"QueryServiceConfig failed (%d)\n", dwError);
                goto cleanup;
            }
            if (pBuf->lpBinaryPathName != NULL)
            {
                wcsncpy_s(szPath, MAX_PATH, pBuf->lpBinaryPathName,
                    MAX_PATH - 1);
                szPath[MAX_PATH - 1] = 0;
                if (pBuf->lpBinaryPathName != szPath)
                    HeapFree(GetProcessHeap(), 0, pBuf->lpBinaryPathName);
            }
            HeapFree(GetProcessHeap(), 0, pBuf);
        }
    }

    if (szPath[0])
    {
        wprintf(L"Path: %s\n", szPath);
        if (!ChangeServiceConfig(schService, SERVICE_NO_CHANGE,
            SERVICE_NO_CHANGE, SERVICE_NO_CHANGE, NULL, NULL, NULL,
            NULL, NULL, NULL, szPath))
        {
            dwError = GetLastError();
            wprintf(L"ChangeServiceConfig failed (%d)\n", dwError);
            goto cleanup;
        }
    }

    wprintf(L"Service %s is now configured with a quoted path\n",
        serviceName);

cleanup:
    if (schService)
        CloseServiceHandle(schService);
    if (schSCManager)
        CloseServiceHandle(schSCManager);
}

