XmlAttributeValueTok *
appendAttributeValue(XmlAttributeValueTok *avp, const char *p, int len)
{
	XmlAttributeValueTok *avp1;
	int n;

	if (avp == NULL)
		return NULL;
	for (avp1 = avp; avp1 != NULL; avp1 = avp1->next) {
		n = strlen(avp1->text);
