static void rescore_suggest(struct spell *sp, struct suggest *su, int max_sug)
{
	struct suggest	*sug;
	int		i, j;

	/*
	 * Rescore the suggestions.  The first suggestion is always
	 * correct.  Score it high enough to be the first suggestion
	 * returned.  Then rescore the rest of the suggestions.
	 */
	for (sug = su->su_sug; sug; sug = sug->su_next)
		rescore_one(sp, sug, 1);

	/*
	 * Now, for each suggestion, score it against the
	 * possible alternatives.  If it matches, score it
	 * higher.
	 */
	for (sug = su->su_sug; sug; sug = sug->su_next)
		if (sug->su_sallang) {
			for (i = 0; i < sug->su_sallang->sl_nlang; i++)
				for (j = 0; j < sug->su_sallang->sl_lang[i].sl_nword; j++)
					rescore_one(sp, sug, sug->su_sallang->sl_lang[i].sl_word[j]);
		}

	/*
	 * Sort the suggestions by score.
	 */
	qsort(su->su_sug, su->su_nsug, sizeof(struct suggest),
	    (int (*)(const void *, const void *))(sp->sp_sug_cmp));

	/*
	 * Remove the excess suggestions.
	 */
	while (su->su_nsug > max_sug) {
		sug = su->su_sug;
		su->su_sug = sug->su_next;
		free(sug);
		su->su_nsug--;
	}
}

