CMS_decrypt_set1_key(CMS_ContentInfo *cms, int i, EVP_PKEY **pkey)
{
    STACK_OF(CMS_RecipientInfo) *ri;
    CMS_RecipientInfo *ri;
    int r = 0;
    EVP_PKEY_CTX *pctx = NULL;
    EVP_PKEY *tmp_pkey = NULL;
    int pkeyid_nid;
    int pkey_nid;
    int ok = 0;

    if (!(ri = CMS_get0_RecipientInfos(cms)))
        goto err;

    if (i >= sk_CMS_RecipientInfo_num(ri))
        goto err;

    ri = sk_CMS_RecipientInfo_value(ri, i);

    if (ri->type != CMS_RECIPINFO_TRANS) {
        CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_NOT_SUPPORTED);
        goto err;
    }

    if (ri->d.ktri->version != 0) {
        CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_UNSUPPORTED_KEY_TRANSPORT_VERSION);
        goto err;
    }

    if (ri->d.ktri->ukm) {
        CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_ONLY_SUPPORTS_SIMPLE_UNWRAP);
        goto err;
    }

    pkeyid_nid = OBJ_obj2nid(ri->d.ktri->keyEncryptionAlgorithm->algorithm);

    if (pkeyid_nid == NID_id_alg_PWRI_KEK) {
        CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_NOT_SUPPORTED);
        goto err;
    }

    if (pkeyid_nid == NID_pbe_WithSHA1And128BitRC2_CBC)
        pkey_nid = NID_rc2_128_cbc;
    else if (pkeyid_nid == NID_pbe_WithSHA1And40BitRC2_CBC)
        pkey_nid = NID_rc2_40_cbc;
    else if (pkeyid_nid == NID_pbe_WithSHA1And3_Key_TripleDES_CBC)
        pkey_nid = NID_des_ede3_cbc;
    else if (pkeyid_nid == NID_pbe_WithSHA1And2_Key_TripleDES_CBC)
        pkey_nid = NID_des_ede3_cbc;
    else if (pkeyid_nid == NID_pbewithSHA1And128BitRC2_CBC)
        pkey_nid = NID_rc2_128_cbc;
    else if (pkeyid_nid == NID_pbewithSHA1And40BitRC2_CBC)
        pkey_nid = NID_rc2_40_cbc;
    else {
        CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_UNSUPPORTED_COMPRESSION_ALGORITHM);
        goto err;
    }

    if (!(pctx = EVP_PKEY_CTX_new(ri->d.ktri->pkey, NULL))) {
        CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, ERR_R_MALLOC_FAILURE);
        goto err;
    }

    if (EVP_PKEY_decrypt_init(pctx) <= 0)
        goto err;

    if (EVP_PKEY_CTX_ctrl(pctx, -1, EVP_PKEY_OP_DECRYPT, EVP_PKEY_CTRL_CMS_DECRYPT, 0, ri->d.ktri) <= 0)
        goto err;

    if (EVP_PKEY_decrypt(pctx, NULL, &r, ri->d.ktri->encryptedKey->data,
                         ri->d.ktri->encryptedKey->length) <= 0)
        goto err;

    if ((unsigned int)r != EVP_PKEY_size(ri->d.ktri->pkey)) {
        CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_WRONG_KEY_SIZE);
        goto err;
    }

    if (!(tmp_pkey = d2i_PublicKey(pkey_nid, NULL,
                                   ri->d.ktri->encryptedKey->data,
                                   ri->d.ktri->encryptedKey->length)))
        goto err;

    if (!EVP_PKEY_copy_parameters(tmp_pkey, ri->d.ktri->pkey))
        goto err;

    if (EVP_PKEY_decrypt(pctx, NULL, &r, ri->d.ktri->encryptedKey->data,
                         ri->d.ktri->encryptedKey->length) <= 0)
        goto err;

    if ((unsigned int)r != EVP_PKEY_size(tmp_pkey)) {
        CMSerr(CMS_F_CMS_DECRYPT_SET1_KEY, CMS_R_WRONG_KEY_SIZE);
        goto err;
    }

    if (!EVP_PKEY_set1_tls_encodetspint(tmp_pkey,
                                       ri->d.ktri->encryptedKey->data,
                                       ri->d.ktri->encryptedKey->length))
        goto err;

    ok = 1;

 err:
    if (!ok)
        EVP_PKEY_free(tmp_pkey);

    EVP_PKEY_CTX_free(pctx);
    *pkey = tmp_pkey;
    return ok;
}

