Status InferenceContet::EpandOutputs(int new_output_size) {
  const int outputs_size = outputs_.size();
  if (new_output_size < outputs_size) {
    return errors::InvalidArgument("Trying to reduce number of outputs of op.");
  }
  outputs_.resize(new_output_size, nullptr);
  output_handle_shapes_and_types_.resize(new_output_size);
  return Status::OK();
}

Generation:
void InferenceContext::ExpandOutputs(size_t delta) {
    if (delta == 0) return;

    mutex_lock l(mu_);

    const size_t old_size = outputs_.size();
    const size_t new_size = old_size + delta;
    if (new_size > old_size) {
      outputs_.resize(new_size);
      output_handle_shapes_and_types_.resize(new_size);
    }
  }

