void KeyedSparseTensorColumn::FillTensor(const string& name, const std::vector<int64>& indices,
                                                    const std::vector<string>& values, Tensor* out) const {
  CHECK_EQ(values.size(), indices.size());
  const int64 N = indices.size();
  if (N == 0) {
    out->Clear();
    return;
  }

  const int64 batch_size = indices[0].size();
  CHECK_EQ(N, batch_size);

  const int64 num_features = num_features_;
  const int64 dense_size = num_features * batch_size;
  const int64 sparse_size = num_features * N;
  const int64 dense_bytes = dense_size * sizeof(float);
  const int64 sparse_bytes = sparse_size * sizeof(float);

  const float default_value = default_value_;
  if (out->NumElements() != dense_size) {
    out->Reshape(TensorShape({dense_size}));
  }

  // If the number of elements is small, or the size of the data is small,
  // or if the user has requested a dense representation, just do a
  // dense fill.
  if (sparse_bytes <= 1024 * 1024 || N <= 1024 || dense_bytes <= sparse_bytes ||
      FillDense(name, default_value, indices, values, out)) {
    return;
  }

  // Otherwise, do a sparse fill.
  const auto& key_to_feature = key_to_feature_;
  const auto& feature_to_index = feature_to_index_;
  const float* dense_default = &default_value;
  const float* sparse_default = &default_value;
  if (default_value == 0.0) {
    dense_default = nullptr;
    sparse_default = nullptr;
  }

  if (dense_bytes <= sparse_bytes) {
    const int64 num_threads =
        std::min<int64>(batch_size,
                        params_.sparse_fill_random_access_dense_threshold);
    auto worker_threads =
        *(params_.worker_threads->mutable_num_threads());
    worker_threads.store(num_threads, std::memory_order_relaxed);
    const int64 num_elements_per_thread = dense_size / num_threads;
    auto worker_threads_copy = params_.worker_threads;
    auto worker_threads_copy_ptr = worker_threads_copy.get();
    auto worker = [&, worker_threads_copy_ptr](int64 start, int64 limit) {
      for (int64 i = start; i < limit; ++i) {
        const int64 row = i;
        const float* dense_values = &out->flat<float>()(row * num_features);
        const float* sparse_values =
            &dense_default
                ? dense_values
                : &sparse_default[feature_to_index[0].second * num_features];
        for (int64 j = 0; j < num_features; ++j) {
          const int64 feature_index = feature_to_index[j].second;
          const int64 index = row * num_features + j;
          if (feature_index < 0) {
            dense_values[j] = default_value;
          } else {
            dense_values[j] = sparse_values[feature_index];
          }
        }
      }
    };
    Shard(worker_threads_copy_ptr, worker_threads_copy_ptr->NumThreads(),
          num_elements_per_thread, worker, 0, batch_size);
  } else {
    const int64 num_threads =
        std::min<int64>(batch_size,
                        params_.sparse_fill_random_access_sparse_threshold);
    auto worker_threads =
        *(params_.worker_threads->mutable_num_threads());
    worker_threads.store(num_threads, std::memory_order_relaxed);
    const int64 num_elements_per_thread = sparse_size / num_threads;
    auto worker_threads_copy = params_.worker_threads;
    auto worker_threads_copy_ptr = worker_threads_copy.get();
    auto worker = [&, worker_threads_copy_ptr](int64 start, int64 limit) {
      for (int64 i = start; i < limit; ++i) {
        const int64 row = i;
        const int64 row_offset = row * num_features;
        const int64 row_size =
            feature_to_index[num_features - 1].second + 1 - row_offset;
        const int64* indices = &indices_[row_offset];
        const int64* indices_end = &indices_[row_offset + row_size];
        const float* values = &values_[row_offset];
        const float* values_end = &values_[row_offset + row_size];
        const float* default_values = dense_default ? dense_values : sparse_default;
        const int64* feature_to_index_end = feature_to_index.data() + num_features;
        const int64* key_to_feature_end = key_to_feature.data() + num_features;
        for (int64 j = 0; j < num_features; ++j) {
          const int64 feature_index = feature_to_index[j].second;
          if (feature_index < 0) {
