pyc_object *get_array_object_generic(const char *buffer, ut32 buf_len, ut32 *out_len, ut32 max_array_len) {
	const char *buf_end = buffer + buf_len;
	pyc_object *ret = NULL;
	ut32 i = 0;

	if (out_len) {
		*out_len = 0;
	}

	while (buffer < buf_end) {
		const char *buf_start = buffer;
		const char *buf_end = buf_start + 1;
		const char *buf_end2 = buf_start + 1;
		ut32 length = 0;
		pyc_object *obj = NULL;
		ut8 byte;

		if (i >= max_array_len) {
			break;
		}

		// Get the length of the object
		do {
			if (buf_end >= buf_end2) {
				return NULL;
			}
			byte = *buf_end2;
			length += (byte & 0x7f) << (7 * (buf_end2 - buf_end));
			buf_end2++;
		} while (byte & 0x80);

		if (buf_end2 > buf_end) {
			return NULL;
		}
		buf_end = buf_end2;

		// Get the object
		switch (*buf_end) {
		case PYC_STRING:
			obj = pyc_string_new(buffer, length);
			break;
		case PYC_UNICODE:
			obj = pyc_unicode_new(buffer, length);
			break;
		case PYC_INT:
			obj = pyc_int_new(buffer, length);
			break;
		case PYC_LIST:
			obj = pyc_list_new(buffer, length);
			break;
		case PYC_DICT:
			obj = pyc_dict_new(buffer, length);
			break;
		case PYC_CODE:
			obj = pyc_code_new(buffer, length);
			break;
		case PYC_OBJ:
			obj = pyc_obj_new(buffer, length);
			break;
		case PYC_SET:
			obj = pyc_set_new(buffer, length);
			break;
		case PYC_FROZENSET:
			obj = pyc_frozenset_new(buffer, length);
			break;
		default:
			break;
		}

		if (!obj) {
			return NULL;
		}

		if (ret == NULL) {
			ret = R_NEW0 (pyc_object);
		}

		if (ret) {
			ret->type = PYC_OBJ;
			ret->value.obj = r_list_newf (sizeof (pyc_object),
					(RListFree) pyc_object_free);
		}

		r_list_append (ret->value.obj, obj);
		buffer = buf_end + length;
		i++;
	}

	if (out_len) {
		*out_len = i;
	}

	return ret;
}

