int json_read_array(struct json_token *tok, struct json_value **val) {
  struct json_value *arr;
  size_t i;
  int err;

  if (tok->type != JSON_TOK_ARRAY_START) {
    return -1;
  }

  arr = calloc(tok->u.array.length, sizeof(struct json_value));
  if (!arr) {
    return -1;
  }

  for (i = 0; i < tok->u.array.length; i++) {
    err = json_read_value(tok->u.array.items[i], &arr[i]);
    if (err) {
      goto error;
    }
  }

  *val = arr;
  return 0;

error:
  json_value_free(arr);
  return -1;
}

