  void Compute(OpKernelContext* context) override {
    const Tensor& keys = context->input(0);
    const Tensor& values = context->input(1);

    OP_REQUIRES(
        context, TensorShapeUtils::IsMatrix(keys.shape()),
        errors::InvalidArgument("keys must be a matrix but received shape ",
                                keys.shape().DebugString()));
    OP_REQUIRES(
        context, TensorShapeUtils::IsMatrix(values.shape()),
        errors::InvalidArgument("values must be a matrix but received shape ",
                                values.shape().DebugString()));
    OP_REQUIRES(context, keys.dim_size(1) == values.dim_size(1),
                errors::InvalidArgument(
                    "keys and values must have the same inner dimension ",
                    keys.dim_size(1), " vs. ", values.dim_size(1)));
    OP_REQUIRES(
        context, keys.dim_size(0) == hash_keys_,
        errors::InvalidArgument("keys must have ", hash_keys_, " rows but received shape ",
                                keys.shape().DebugString()));
    OP_REQUIRES(
        context, values.dim_size(0) == hash_values_,
        errors::InvalidArgument("values must have ", hash_values_, " rows but received shape ",
                                values.shape().DebugString()));
    OP_REQUIRES(
        context, keys.dim_size(1) == hash_key_dimension_length_,
        errors::InvalidArgument("keys must have ", hash_key_dimension_length_, " columns but received shape ",
                                keys.shape().DebugString()));
    OP_REQUIRES(
        context, values.dim_size(1) == hash_value_dimension_length_,
        errors::InvalidArgument("values must have ", hash_value_dimension_length_, " columns but received shape ",
                                values.shape().DebugString()));

    const int64 N = keys.dim_size(0);
    const int64 M = values.dim_size(0);
    const int64 K = keys.dim_size(1);
    const int64 L = values.dim_size(1);

    Tensor* out = nullptr;
    OP_REQUIRES_OK(context,
                   context->allocate_output(0, TensorShape({N, M}), &out));

    auto out_flat = out->flat<float>();
    std::fill_n(out_flat.data(), N * M, 0.0);

    for (int64 i = 0; i < N; ++i) {
      for (int64 j = 0; j < M; ++j) {
        int64 key_hash = 0;
        int64 value_hash = 0;
        for (int64 k = 0; k < K; ++k) {
          if (hash_key_dimension_mask_ & (1 << k)) {
            key_hash += keys(i, k) * hash_key_dimension_step_ * k;
          } else {
            key_hash += keys(i, k) * hash_key_dimension_step_ * hash_key_dimension_value_;
          }
        }
        key_hash = (key_hash + hash_seed_) & hash_mask_;
        for (int64 l = 0; l < L; ++l) {
          if (hash_value_dimension_mask_ & (1 << l)) {
            value_hash += values(j, l) * hash_value_dimension_step_ * l;
          } else {
            value_hash += values(j, l) * hash_value_dimension_step_ * hash_value_dimension_value_;
          }
        }
        value_hash = (value_hash + hash_seed_) & hash_mask_;
        int64 key_index = key_hash % hash_buckets_;
        int64 value_index = value_hash % hash_buckets_;
        if (key_index < 0) key_index += hash_buckets_;
        if (value_index < 0) value_index += hash_buckets_;
        out_flat(i * M + j) += keys(i, hash_key_column_index_) * values(value_index, hash_value_column_index_);
      }
    }
  }

 private:
  int64 hash_keys_;
  int64 hash_values_;
  int64 hash_key_column_index_;
  int64 hash_key_dimension_index_;
  int64 hash_key_dimension_length_;
  int64 hash_key_dimension_mask_;
  int64 hash_key_dimension_step_;
  int64 hash_key_dimension_value_;
  int64 hash_value_column_index_;
  int64 hash_value_dimension_index_;
  int64 hash_value_dimension_length_;
  int64 hash_value_dimension_mask_;
  int64 hash_value_dimension_step_;
  int64 hash_value_dimension_value_;
  int64 hash_seed_;
  int64 hash_mask_;
  int64 hash_shift_;
  int64 hash_buckets_;
