void napi_throw_range_error(napi_env env, const char* code, const char* msg)
{
  napi_handle_scope scope;
  napi_value error;
  napi_value code_value;
  napi_value msg_value;
  CHECK_NEW_FROM_UTF8(env, code_value, code, NAPI_AUTO_LENGTH);
  CHECK_NEW_FROM_UTF8(env, msg_value, msg, NAPI_AUTO_LENGTH);
  NAPI_CALL_BASE(env, napi_create_range_error(env, NULL, code_value, msg_value, &error));
  NAPI_CALL_BASE(env, napi_throw(env, error));
  napi_clear_last_error();
}

