/*
 * spell_suggest_file() {{{1
 *
 * Read suggestions from a file and return them.
 */
    static char_u *spell_suggest_file(
	char_u	    *preword,
	char_u	    *fname)
{
    char_u	*retval = NULL;
    FILE	*fp;
    char_u	*line;
    char_u	*p;
    char_u	*s;
    int		len;
    int		did_something = FALSE;

    fp = mch_fopen((char *)fname, READBIN);
    if (fp == NULL)
	return NULL;

    if (preword != NULL && *preword != NUL)
    {
	// Check the preword: if it matches the first word on a line, use the
	// line.
	for (;;)
	{
	    line = vim_fgets(IObuff, IOSIZE, fp);
	    if (line == NULL)
		break;
	    p = skiptowhite(line);
	    if (p == line)
		continue;
	    if (STRNCMP(line, preword, p - line) == 0)
	    {
		retval = vim_strsave(line);
		did_something = TRUE;
		break;
	    }
	}
    }

    if (!did_something)
    {
	// Check the entire line.
	while ((line = vim_fgets(IObuff, IOSIZE, fp)) != NULL)
	{
	    len = (int)STRLEN(line);
	    if (len == 0)
		continue;
	    if (line[len - 1] != '\n')
	    {
		len = IOSIZE - 1;
		line[len] = '\n';
		line[len + 1] = NUL;
	    }
	    if (len >= 2 && line[len - 2] == '\r')
		line[len - 2] = NUL;

	    p = skiptowhite(line);
	    if (p == line)
		continue;

	    // Check if the line starts with a word character, like the
	    // word that was misspelled.  If not, skip the line.
	    s = line;
	    while (s < p)
		if (!vim_iswordc(*s++))
		    break;
	    if (s == p)
		continue;

	    if (retval != NULL)
		retval = concat_str(retval, p);
	    else
		retval = vim_strsave(p);
	}
    }

    fclose(fp);
    return retval;
}

